def word_break(s, words):
    from collections import defaultdict

    def dfs(start):
        if start == len(s):
            return True
        if start in memo:
            return memo[start]

        for end in range(start + 1, len(s) + 1):
            if s[start:end] in words and dfs(end):
                memo[start] = True
                return True

        memo[start] = False
        return False

    memo = defaultdict(bool)
    return dfs(0)
